#include <iostream>
#include <string>

class GameEntity {
private:
    std::string name;
    int health;
    int attack;

public:
    // Constructor using 'this' to disambiguate
    GameEntity(std::string name, int health, int attack) {
        this->name = name;        // 'this->' refers to the member
        this->health = health;
        this->attack = attack;
        std::cout << "Entity " << this->name << " created!" << std::endl;
    }

    // Returning *this for method chaining
    GameEntity& setName(const std::string& name) {
        this->name = name;
        return *this;  // Return the current object
    }

    GameEntity& setHealth(int health) {
        this->health = health;
        return *this;
    }

    GameEntity& setAttack(int attack) {
        this->attack = attack;
        return *this;
    }

    // Method chaining example
    GameEntity& buff(int amount) {
        this->attack += amount;
        std::cout << this->name << " buffed by " << amount << " (Attack: " << this->attack << ")" << std::endl;
        return *this;
    }

    // Comparing objects using 'this'
    bool isSame(const GameEntity& other) const {
        return this == &other;  // Compare memory addresses
    }

    // Checking if two entities have same name
    bool hasSameName(const GameEntity& other) const {
        return this->name == other.name;
    }

    void display() const {
        std::cout << "Entity: " << name << " (HP: " << health << ", ATK: " << attack << ")" << std::endl;
    }

    // 'this' pointer with const
    void constMethod() const {
        // this is const in const methods
        // this->name = "NewName";  // ERROR!
        std::cout << "Const method called for " << this->name << std::endl;
    }

    // Function that returns the object itself
    GameEntity* getPointer() {
        return this;
    }

    // Function that returns a reference to the object
    GameEntity& getReference() {
        return *this;
    }
};

int main() {
    std::cout << "=== The 'this' Pointer ===" << std::endl;

    GameEntity hero("Aragorn", 100, 20);
    hero.display();

    std::cout << "\n=== Method Chaining ===" << std::endl;
    hero.setName("Aragorn the Great")
        .setHealth(150)
        .setAttack(30)
        .buff(10);

    hero.display();

    std::cout << "\n=== Comparing Objects ===" << std::endl;
    GameEntity hero2("Aragorn the Great", 150, 40);

    std::cout << "hero.isSame(hero)? " << hero.isSame(hero) << std::endl;
    std::cout << "hero.isSame(hero2)? " << hero.isSame(hero2) << std::endl;
    std::cout << "hero.hasSameName(hero2)? " << hero.hasSameName(hero2) << std::endl;

    std::cout << "\n=== Getting 'this' Pointer ===" << std::endl;
    GameEntity* ptr = hero.getPointer();
    ptr->display();

    GameEntity& ref = hero.getReference();
    ref.display();

    std::cout << "\n=== Const Method ===" << std::endl;
    hero.constMethod();

    return 0;
}

phase2.brokenCode:
#include <iostream>
#include <string>

class Player {
private:
    std::string name;

public:
    void setName(const std::string& name) {
        // Forgot 'this->', so name = name (does nothing!)
        name = name;
    }

    void display() const {
        std::cout << "Name: " << name << std::endl;
    }
};

int main() {
    Player p;
    p.setName("Hero");
    p.display();  // Outputs nothing!
    return 0;
}

phase2.explanation:
You forgot `this->` in the setter!

**What's happening:**
```cpp
void setName(const std::string& name) {
    name = name;  // Both refer to the parameter!
    // Should be: this->name = name;
}
```

The compiler sees `name = name` and thinks you're assigning the parameter to itself.

**The fix:**
```cpp
void setName(const std::string& name) {
    this->name = name;  // ← Use 'this->'
}
```

**PlusPlus-chan says:**
"Always use `this->` when you have a parameter with the same name as a member. It's the only way to disambiguate."

