#include <iostream>
#include <string>

class Character {
private:
    std::string name;
    int health;
    int attack;

public:
    Character(std::string name, int health, int attack) {
        this->name = name;
        this->health = health;
        this->attack = attack;
        std::cout << "Character " << this->name << " created!" << std::endl;
    }

    Character& setName(std::string name) {
        this->name = name;
        return *this;
    }

    Character& setHealth(int health) {
        this->health = health;
        return *this;
    }

    Character& setAttack(int attack) {
        this->attack = attack;
        return *this;
    }

    Character& buff(int amount) {
        this->attack += amount;
        std::cout << this->name << " buffed! Attack: " << this->attack << std::endl;
        return *this;
    }

    void display() const {
        std::cout << "Character: " << this->name 
                  << " (HP: " << this->health << ", ATK: " << this->attack << ")" << std::endl;
    }

    bool isSame(const Character& other) const {
        return this == &other;
    }
};

int main() {
    Character hero("Aragorn", 100, 20);

    hero.setHealth(150)
        .setAttack(25)
        .buff(10);

    hero.display();

    Character hero2("Legolas", 80, 30);

    std::cout << "hero.isSame(hero)? " << hero.isSame(hero) << std::endl;
    std::cout << "hero.isSame(hero2)? " << hero.isSame(hero2) << std::endl;

    return 0;
}
